class Solution:
    def minChanges(self, nums, k):
        n = len(nums)
        m = n // 2
        pairs = [(nums[i], nums[n - 1 - i]) for i in range(m)]
        best = None
        for X in range(k + 1):
            total = 0
            for a, b in pairs:
                if abs(a - b) == X:
                    cost = 0
                elif (0 <= a + X <= k) or (0 <= a - X <= k) or (0 <= b + X <= k) or (0 <= b - X <= k):
                    cost = 1
                else:
                    cost = 2
                total += cost
            if best is None or total < best:
                best = total
        return best

