var minChanges = function(nums, k) {
    const n = nums.length;
    const m = Math.floor(n / 2);
    const diff = new Array(k + 2).fill(0);
    const deltaCnt = new Array(k + 1).fill(0);
    for (let i = 0; i < m; i++) {
        const a = nums[i];
        const b = nums[n - 1 - i];
        const delta = Math.abs(a - b);
        const M = Math.max(a, k - a, b, k - b);
        diff[0] += 1;
        diff[Math.min(M, k) + 1] -= 1;
        deltaCnt[delta] += 1;
    }
    let best = Infinity;
    let acc = 0;
    for (let x = 0; x <= k; x++) {
        acc += diff[x];
        const discount = acc + deltaCnt[x];
        const cost = 2 * m - discount;
        if (cost < best) best = cost;
    }
    return best;
};
